         let cmd = model.update(MailMsg::Terminal(ctrl_t));
         assert!(matches!(cmd, Cmd::None));
         let after = crate::tui_theme::current_theme_id();
         assert_ne!(before, after);
+        crate::tui_theme::init_named_theme("default");
     }

